  1	import * as React from 'react';
  2	import {
  3	  ClipboardCopy,
  4	  DescriptionList,
  5	  DescriptionListDescription,
  6	  DescriptionListGroup,
  7	  DescriptionListTerm,
  8	} from '@patternfly/react-core';
  9	import { useTranslation } from 'react-i18next';
 10	import { Link } from 'react-router-dom-v5-compat';
 11	import { getPLRLogSnippet } from '../logs/pipelineRunLogSnippet';
 12	import RunDetailsErrorLog from '../logs/RunDetailsErrorLog';
 13	import { getReferenceForModel } from '../pipelines-overview/utils';
 14	import Status from '../status/Status';
 15	import { ExternalLink } from '../utils/link';
 16	import { TaskRunModel } from '../../models';
 17	import { Timestamp } from '@openshift-console/dynamic-plugin-sdk';
 18	import { ComputedStatus, PipelineRunKind } from '../../types';
 19	import {
 20	  pipelineRunFilterReducer,
 21	  pipelineRunTitleFilterReducer,
 22	} from '../utils/pipeline-filter-reducer';
 23	import {
 24	  getImageUrl,
 25	  getSbomLink,
 26	  getSbomTaskRun,
 27	  hasExternalLink,
 28	  pipelineRunDuration,
 29	} from '../utils/pipeline-utils';
 30	import { convertBackingPipelineToPipelineResourceRefProps } from './utils';
 31	import RepositoryLinkList from './RepositoryLinkList';
 32	import PipelineRunVulnerabilities from '../pipelines-list/status/PipelineRunVulnerabilities';
 33	import { useTaskRuns } from '../hooks/useTaskRuns';
 34	import { useMultiClusterProxyService } from '../hooks/useMultiClusterProxyService';
 35	import TriggeredBySection from './TriggeredBySection';
 36	import PipelineResourceRef from '../triggers-details/PipelineResourceRef';
 37	import WorkspaceResourceLinkList from '../workspaces/WorkspaceResourceLinkList';
 38	
 39	export type PipelineRunCustomDetailsProps = {
 40	  pipelineRun: PipelineRunKind;
 41	};
 42	
 43	const PipelineRunCustomDetails: React.FC<PipelineRunCustomDetailsProps> = ({
 44	  pipelineRun,
 45	}) => {
 46	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 47	  const { isResourceManagedByKueue } = useMultiClusterProxyService({ managedBy: pipelineRun?.spec?.managedBy });
 48	  const plrStatus = pipelineRunFilterReducer(pipelineRun);
 49	  const pipelineRunFinished =
 50	    plrStatus !== ComputedStatus.Running &&
 51	    plrStatus !== ComputedStatus.Pending &&
 52	    plrStatus !== ComputedStatus.Cancelling;
 53	  const [taskRuns, taskRunsLoaded] = useTaskRuns(
 54	    pipelineRun?.metadata?.namespace,
 55	    pipelineRun?.metadata?.name,
 56	    { 
 57	      pipelineRunFinished,
 58	      pipelineRunManagedBy: pipelineRun?.spec?.managedBy
 59	    },
 60	  );
 61	
 62	  const sbomTaskRun = taskRunsLoaded ? getSbomTaskRun(taskRuns) : null;
 63	  const buildImage = getImageUrl(pipelineRun);
 64	  const linkToSbom = getSbomLink(sbomTaskRun);
 65	  const isExternalLink = hasExternalLink(sbomTaskRun);
 66	  return (
 67	    <>
 68	      <DescriptionList>
 69	        <DescriptionListGroup>
 70	          <DescriptionListTerm>{t('Status')}</DescriptionListTerm>
 71	          <DescriptionListDescription>
 72	            <Status
 73	              status={pipelineRunFilterReducer(pipelineRun)}
 74	              title={pipelineRunTitleFilterReducer(pipelineRun)}
 75	            />
 76	          </DescriptionListDescription>
 77	        </DescriptionListGroup>
 78	        {taskRunsLoaded && (
 79	          <RunDetailsErrorLog
 80	            logDetails={getPLRLogSnippet(pipelineRun, taskRuns)}
 81	            namespace={pipelineRun.metadata.namespace}
 82	            isResourceManagedByKueue={isResourceManagedByKueue}
 83	            pipelineRunName={pipelineRun.metadata.name}
 84	          />
 85	        )}
 86	        <DescriptionListGroup>
 87	          <DescriptionListTerm>{t('Vulnerabilities')}</DescriptionListTerm>
 88	          <DescriptionListDescription>
 89	            <PipelineRunVulnerabilities pipelineRun={pipelineRun} />
 90	          </DescriptionListDescription>
 91	        </DescriptionListGroup>
 92	
 93	        <DescriptionListGroup>
 94	          <DescriptionListTerm>{t('Pipeline')}</DescriptionListTerm>
 95	          <DescriptionListDescription>
 96	            <PipelineResourceRef
 97	              {...convertBackingPipelineToPipelineResourceRefProps(pipelineRun)}
 98	            />
 99	          </DescriptionListDescription>
100	        </DescriptionListGroup>
101	        {buildImage && sbomTaskRun && (
102	          <DescriptionListGroup>
103	            <DescriptionListTerm data-test="download-sbom">
104	              {t('Download SBOM')}
105	            </DescriptionListTerm>
106	            <DescriptionListDescription>
107	              <ClipboardCopy
108	                isReadOnly
109	                hoverTip={t('Copy')}
110	                clickTip={t('Copied')}
111	              >
112	                {`cosign download sbom ${buildImage}`}
113	              </ClipboardCopy>
114	              <ExternalLink href="https://docs.sigstore.dev/cosign/installation">
115	                {t('Install Cosign')}
116	              </ExternalLink>
117	            </DescriptionListDescription>
118	          </DescriptionListGroup>
119	        )}
120	        {sbomTaskRun && (
121	          <DescriptionListGroup>
122	            <DescriptionListTerm data-test="view-sbom">
123	              {t('SBOM')}
124	            </DescriptionListTerm>
125	            <DescriptionListDescription>
126	              {isExternalLink &&
127	              linkToSbom &&
128	              (linkToSbom.startsWith('http://') ||
129	                linkToSbom.startsWith('https://')) ? (
130	                <ExternalLink href={linkToSbom}>{t('View SBOM')}</ExternalLink>
131	              ) : (
132	                <Link
133	                  to={`/k8s/ns/${
134	                    sbomTaskRun.metadata.namespace
135	                  }/${getReferenceForModel(TaskRunModel)}/${
136	                    sbomTaskRun.metadata.name
137	                  }/logs`}
138	                >
139	                  {t('View SBOM')}
140	                </Link>
141	              )}
142	            </DescriptionListDescription>
143	          </DescriptionListGroup>
144	        )}
145	        <DescriptionListGroup>
146	          <DescriptionListTerm>{t('Start time')}</DescriptionListTerm>
147	          <DescriptionListDescription>
148	            <Timestamp timestamp={pipelineRun?.status?.startTime} />
149	          </DescriptionListDescription>
150	        </DescriptionListGroup>
151	        <DescriptionListGroup>
152	          <DescriptionListTerm>{t('Completion time')}</DescriptionListTerm>
153	          <DescriptionListDescription>
154	            <Timestamp timestamp={pipelineRun?.status?.completionTime} />
155	          </DescriptionListDescription>
156	        </DescriptionListGroup>
157	        <DescriptionListGroup>
158	          <DescriptionListTerm>{t('Duration')}</DescriptionListTerm>
159	          <DescriptionListDescription>
160	            {pipelineRunDuration(pipelineRun)}
161	          </DescriptionListDescription>
162	        </DescriptionListGroup>
163	        {pipelineRun.spec?.timeouts && (
164	          <DescriptionListGroup>
165	            <DescriptionListTerm>{t('Timeouts')}</DescriptionListTerm>
166	            <DescriptionListDescription>
167	              {pipelineRun.spec?.timeouts?.pipeline}
168	            </DescriptionListDescription>
169	          </DescriptionListGroup>
170	        )}
171	      </DescriptionList>
172	      <TriggeredBySection pipelineRun={pipelineRun} />
173	      <RepositoryLinkList pipelineRun={pipelineRun} />
174	      <WorkspaceResourceLinkList
175	        workspaces={pipelineRun.spec.workspaces}
176	        namespace={pipelineRun.metadata.namespace}
177	        ownerResourceName={pipelineRun.metadata.name}
178	      />
179	    </>
180	  );
181	};
182	
183	export default PipelineRunCustomDetails;

